+    databufp: *mut *mut c_void,
+) -> c_int {
+    if offset < 2 || len > 255 || align == 0 || (align & (align - 1)) != 0 || align > 8 {
+        return -1;
+    }
+    // Types 0 and 1 are reserved for padding.
+    if typ == 0 || typ == 1 {
