+#[test]
+fn inet6_opt_next_iterates_options() {
+    let mut buf = [0u8; 64];
+    let off = unsafe { inet6_opt_init(buf.as_mut_ptr() as *mut _, buf.len() as i32) };
+
+    // Append two options with different types.
+    let off2 = unsafe {
+        inet6_opt_append(
+            buf.as_mut_ptr() as *mut _,
+            buf.len() as i32,
+            off,
+            10,
+            2,
+            1,
+            ptr::null_mut(),
+        )
+    };
+    assert!(off2 > 0);
+
+    let off3 = unsafe {
+        inet6_opt_append(
+            buf.as_mut_ptr() as *mut _,
+            buf.len() as i32,
+            off2,
+            20,
+            3,
+            1,
+            ptr::null_mut(),
+        )
+    };
+    assert!(off3 > 0);
+
+    let total = unsafe { inet6_opt_finish(buf.as_mut_ptr() as *mut _, buf.len() as i32, off3) };
+    assert!(total > 0);
+
+    // Iterate: should find type 10 first, then type 20.
+    let mut typ: u8 = 0;
+    let mut len: usize = 0;
+    let next1 = unsafe {
+        inet6_opt_next(
+            buf.as_mut_ptr() as *mut _,
+            total,
+            off,
+            &mut typ,
+            &mut len,
+            ptr::null_mut(),
+        )
+    };
+    assert!(next1 > 0);
+    assert_eq!(typ, 10);
+
+    let next2 = unsafe {
+        inet6_opt_next(
+            buf.as_mut_ptr() as *mut _,
+            total,
+            next1,
+            &mut typ,
+            &mut len,
+            ptr::null_mut(),
+        )
+    };
+    assert!(next2 > 0);
+    assert_eq!(typ, 20);
+}
