+            ptr::null_mut(),
+        )
+    };
+    assert!(found > 0, "should find type 20");
+    assert_eq!(len, 3);
+
+    // Find type 99 (doesn't exist).
+    let not_found = unsafe {
+        inet6_opt_find(
+            buf.as_mut_ptr() as *mut _,
+            total,
+            off,
+            99,
+            ptr::null_mut(),
+            ptr::null_mut(),
+        )
+    };
+    assert_eq!(not_found, -1);
+}
