+#[test]
+fn inet6_rth_init_too_small_returns_null() {
+    let mut buf = [0u8; 4]; // Too small for any routing header.
+    let bp = unsafe { inet6_rth_init(buf.as_mut_ptr() as *mut _, 4, 0, 1) };
+    assert!(bp.is_null());
+}
